export const assets = {
  // Player
  playerCar: () => import('../assets/cars-racing/cars/png/car_17_v3_440x680.png'),

  // NPCs
  npcCarYellow: () => import('../assets/cars-racing/cars/png/car_10_440x680.png'),
  npcCarBlue: () => import('../assets/cars-racing/cars/png/car_23_440x680.png'),

  // Background / Track
  trackAtlas: () => import('../assets/cars-racing/atlas/png/atlas_01_color2_2048x2048.png'),
  background: () => import('../assets/cars-racing/atlas/png/background_1080x1920.png'),
  logo: () => import('../assets/cars-racing/atlas/png/logo_960x360.png'),
};

import { Events } from 'phaser';

// Singleton EventBus
export const EventBus = new Events.EventEmitter();

import { create } from 'zustand';

type GameState = 'START' | 'PLAYING' | 'GAMEOVER';

interface GameStore {
  gameState: GameState;
  score: number; // Represents laps
  timeLeft: number;
  setGameState: (state: GameState) => void;
  setScore: (score: number) => void;
  addScore: (delta: number) => void;
  setTimeLeft: (time: number) => void;
  resetGame: () => void;
}

export const useGameStore = create<GameStore>((set) => ({
  gameState: 'START',
  score: 0,
  timeLeft: 90,
  setGameState: (state) => set({ gameState: state }),
  setScore: (score) => set({ score }),
  addScore: (delta) => set((state) => ({ score: state.score + delta })),
  setTimeLeft: (time) => set({ timeLeft: time }),
  resetGame: () => set({ score: 0, timeLeft: 90, gameState: 'PLAYING' }),
}));

import playerCar from '../assets/cars-racing/cars/png/car_17_v3_440x680.png';
import npcCarYellow from '../assets/cars-racing/cars/png/car_10_440x680.png';
import npcCarBlue from '../assets/cars-racing/cars/png/car_23_440x680.png';
import trackAtlas from '../assets/cars-racing/atlas/png/atlas_01_color2_2048x2048.png';
import background from '../assets/cars-racing/atlas/png/background_1080x1920.png';
import logo from '../assets/cars-racing/atlas/png/logo_960x360.png';

export const AssetUrls = {
  playerCar,
  npcCarYellow,
  npcCarBlue,
  trackAtlas,
  background,
  logo
};

import { Scene } from 'phaser';
import { AssetUrls } from '../assets';

export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    this.load.image('player_car', AssetUrls.playerCar);
    this.load.image('npc_car_yellow', AssetUrls.npcCarYellow);
    this.load.image('npc_car_blue', AssetUrls.npcCarBlue);
    this.load.image('track_atlas', AssetUrls.trackAtlas);
    this.load.image('background', AssetUrls.background);
    this.load.image('logo', AssetUrls.logo);

    // Auto-generate fallback textures for load errors
    this.load.on('loaderror', (file: any) => {
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, w, h);
      g.destroy();
    });
  }

  create() {
    this.scene.start('MainGame');
  }
}

import Phaser from 'phaser';
import { Boot } from './scenes/Boot';
import { MainGame } from './scenes/MainGame';

export const GAME_CONFIG: Phaser.Types.Core.GameConfig = {
  type: Phaser.AUTO,
  parent: 'game-container',
  width: 540,
  height: 960,
  scene: [Boot, MainGame],
  physics: {
    default: 'arcade',
    arcade: {
      gravity: { y: 0, x: 0 },
      debug: false
    }
  },
  scale: {
    mode: Phaser.Scale.FIT,
    autoCenter: Phaser.Scale.CENTER_BOTH
  },
  backgroundColor: '#87CEEB'
};

import Phaser from 'phaser';
import { EventBus } from '../EventBus';
import { useGameStore } from '../../store/gameStore';

const MAX_SPEED = 800;
const ACCEL = 300;
const FRICTION = 200;
const TURN_SPEED = 300;
const LAP_DISTANCE = 10000;
const GAME_DURATION = 90;

export class MainGame extends Phaser.Scene {
  private player!: Phaser.Physics.Arcade.Sprite;
  private trackTile!: Phaser.GameObjects.TileSprite;
  private npcGroup!: Phaser.Physics.Arcade.Group;
  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  private spaceKey!: Phaser.Input.Keyboard.Key;

  private currentSpeed = 0;
  private distance = 0;
  private isPlaying = false;
  private timerEvent: Phaser.Time.TimerEvent | null = null;
  private lastHitTime = 0;

  constructor() {
    super('MainGame');
  }

  create() {
    const width = this.scale.width;
    const height = this.scale.height;

    // Track
    this.trackTile = this.add.tileSprite(0, 0, width, height, 'track_atlas').setOrigin(0, 0);

    // Player
    this.player = this.physics.add.sprite(width / 2, height - 150, 'player_car');
    this.player.setScale(0.14);
    this.player.setCollideWorldBounds(true);
    // Adjust hitbox
    (this.player.body as Phaser.Physics.Arcade.Body).setSize(300, 600);

    // NPCs
    this.npcGroup = this.physics.add.group();

    // Input
    this.cursors = this.input.keyboard!.createCursorKeys();
    this.spaceKey = this.input.keyboard!.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE);

    // Collision
    this.physics.add.overlap(this.player, this.npcGroup, this.onHitNpc, undefined, this);

    // Events
    EventBus.on('start-game', this.startGame, this);

    // Default state: wait for start
    this.isPlaying = false;
  }

  private startGame() {
    this.isPlaying = true;
    this.currentSpeed = 0;
    this.distance = 0;
    this.lastHitTime = 0;
    this.player.setPosition(this.scale.width / 2, this.scale.height - 150);
    this.npcGroup.clear(true, true);

    useGameStore.getState().resetGame();
    useGameStore.getState().setTimeLeft(GAME_DURATION);

    if (this.timerEvent) {
      this.timerEvent.destroy();
    }

    this.timerEvent = this.time.addEvent({
      delay: 1000,
      callback: this.tickTimer,
      callbackScope: this,
      loop: true
    });

    this.time.addEvent({
      delay: 2000,
      callback: this.spawnNpc,
      callbackScope: this,
      loop: true
    });
  }

  private tickTimer() {
    if (!this.isPlaying) return;
    const store = useGameStore.getState();
    const newTime = store.timeLeft - 1;
    store.setTimeLeft(newTime);

    if (newTime <= 0) {
      this.gameOver();
    }
  }

  private spawnNpc() {
    if (!this.isPlaying) return;
    // Spawn ahead of player (y = -100)
    const x = Phaser.Math.Between(50, this.scale.width - 50);
    const texture = Phaser.Math.FloatBetween(0, 1) > 0.5 ? 'npc_car_yellow' : 'npc_car_blue';
    const npc = this.npcGroup.create(x, -100, texture) as Phaser.Physics.Arcade.Sprite;
    npc.setScale(0.14);
    // Store its base speed
    npc.setData('baseSpeed', Phaser.Math.Between(200, 400));
    (npc.body as Phaser.Physics.Arcade.Body).setSize(300, 600);
  }

  private onHitNpc(p: any, n: any) {
    const now = this.time.now;
    if (now - this.lastHitTime > 500) {
      this.currentSpeed *= 0.4; // Lose 60% speed
      this.lastHitTime = now;

      // Visual feedback: brief shake
      this.tweens.add({
        targets: this.player,
        x: this.player.x + Phaser.Math.Between(-10, 10),
        duration: 50,
        yoyo: true,
        repeat: 3
      });
    }
  }

  private gameOver() {
    this.isPlaying = false;
    if (this.timerEvent) {
      this.timerEvent.destroy();
    }
    useGameStore.getState().setGameState('GAMEOVER');
  }

  update(time: number, delta: number) {
    if (!this.isPlaying) {
      (this.player.body as Phaser.Physics.Arcade.Body).setVelocity(0, 0);
      return;
    }

    const dt = delta / 1000;

    // Acceleration & Braking
    if (this.spaceKey.isDown) {
      this.currentSpeed += ACCEL * dt;
    } else {
      this.currentSpeed -= FRICTION * dt;
    }

    this.currentSpeed = Phaser.Math.Clamp(this.currentSpeed, 0, MAX_SPEED);

    // Steering
    let vx = 0;
    if (this.currentSpeed > 0) {
      if (this.cursors.left.isDown) {
        vx = -TURN_SPEED;
        this.player.angle = -5;
      } else if (this.cursors.right.isDown) {
        vx = TURN_SPEED;
        this.player.angle = 5;
      } else {
        this.player.angle = 0;
      }
    } else {
      this.player.angle = 0;
    }

    (this.player.body as Phaser.Physics.Arcade.Body).setVelocityX(vx);

    // Track scroll
    this.trackTile.tilePositionY -= this.currentSpeed * dt;

    // Distance & Laps
    this.distance += this.currentSpeed * dt;
    if (this.distance >= LAP_DISTANCE) {
      this.distance -= LAP_DISTANCE;
      useGameStore.getState().addScore(1);
    }

    // NPC movement relative to player speed
    this.npcGroup.children.iterate((child) => {
      const npc = child as Phaser.Physics.Arcade.Sprite;
      const baseSpeed = npc.getData('baseSpeed');
      // If player speed is 800, and npc baseSpeed is 300
      // the npc should move downwards on screen at 500 (800 - 300)
      const relativeVelocityY = this.currentSpeed - baseSpeed;
      (npc.body as Phaser.Physics.Arcade.Body).setVelocityY(relativeVelocityY);

      // Remove off-screen NPCs
      if (npc.y > this.scale.height + 200) {
        npc.destroy();
      }
      return true;
    });
  }

  shutdown() {
    EventBus.off('start-game', this.startGame, this);
  }
}

import { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { GAME_CONFIG } from './game/main';
import { useGameStore } from './store/gameStore';
import { StartScreen } from './components/StartScreen';
import { GameOverScreen } from './components/GameOverScreen';
import { HUD } from './components/HUD';

function App() {
  const initialized = useRef(false);
  const gameState = useGameStore(state => state.gameState);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;
    const game = new Phaser.Game(GAME_CONFIG);

    return () => {
      game.destroy(true);
      initialized.current = false;
    };
  }, []);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#87CEEB] flex justify-center items-center font-mono font-bold select-none">
      <div className="relative w-[540px] h-[960px] max-w-full max-h-full">
        {/* Phaser Canvas Container */}
        <div id="game-container" className="absolute inset-0 w-full h-full" />

        {/* React UI Overlays */}
        {gameState === 'START' && <StartScreen />}
        {gameState === 'PLAYING' && <HUD />}
        {gameState === 'GAMEOVER' && <GameOverScreen />}
      </div>
    </div>
  );
}

export default App;

import { EventBus } from '../game/EventBus';
import { useGameStore } from '../store/gameStore';

export const StartScreen = () => {
  const setGameState = useGameStore(state => state.setGameState);

  const handleStart = () => {
    setGameState('PLAYING');
    EventBus.emit('start-game');
  };

  return (
    <div className="absolute inset-0 flex flex-col items-center justify-center bg-[#87CEEB] z-10 p-4">
      {/* Title Card */}
      <div className="bg-white border-4 border-[#1A1A1A] p-6 mb-12 shadow-[8px_8px_0_#1A1A1A]">
        <h1 className="text-4xl text-[#FF4500] text-center mb-2">K12 欢乐赛车</h1>
        <p className="text-[#1A1A1A] text-lg text-center">快乐竞速，挑战极限！</p>
      </div>

      {/* Instructions */}
      <div className="bg-white border-4 border-[#1A1A1A] p-6 mb-12 shadow-[8px_8px_0_#1A1A1A] max-w-sm w-full text-[#1A1A1A]">
        <h2 className="text-2xl text-center mb-4 text-[#FFD700] bg-[#1A1A1A] py-1">操作说明</h2>
        <ul className="space-y-4 text-lg">
          <li className="flex justify-between items-center">
            <span>← →</span>
            <span>左右转向</span>
          </li>
          <li className="flex justify-between items-center">
            <span>Space (空格)</span>
            <span>长按加速</span>
          </li>
          <li className="flex justify-between items-center">
            <span>目标</span>
            <span>90秒跑出最多圈数</span>
          </li>
        </ul>
      </div>

      {/* Start Button */}
      <button
        onClick={handleStart}
        className="bg-[#FFD700] border-4 border-[#1A1A1A] text-[#1A1A1A] text-3xl py-4 px-12 shadow-[8px_8px_0_#1A1A1A] active:shadow-[0_0_0_#1A1A1A] active:translate-y-2 transition-all"
      >
        开始游戏
      </button>
    </div>
  );
};

